class FinancialBusinessLogic:
    """Encapsulates all business logic for the financial services."""

    _transaction_counter = 0

    @classmethod
    def _generate_transaction_id(cls):
        cls._transaction_counter += 1
        return f"TXN{datetime.utcnow().strftime('%Y%m%d%H%M%S')}{cls._transaction_counter:06d}"

    @staticmethod
    def get_balance(account_id):
        logger.info(f"Business Logic: Getting balance for account {account_id}")

        if not account_id or account_id.strip() == "":
            return {
                "status_code": "ERROR_INVALID_INPUT",
                "status_message": "Account ID cannot be empty.",
            }

        account = accounts_db.get(account_id)
        if account is None:
            return {
                "status_code": "ERROR_NOT_FOUND",
                "status_message": f"Account '{account_id}' not found.",
            }

        if not account["is_active"]:
            return {
                "status_code": "WARNING_INACTIVE",
                "status_message": f"Account '{account_id}' is inactive.",
                "account_id": account_id,
                "balance": account["balance"],
                "currency": account["currency"],
            }

        return {
            "status_code": "SUCCESS",
            "status_message": "Balance retrieved successfully.",
            "account_id": account_id,
            "balance": account["balance"],
            "currency": account["currency"],
        }

    @classmethod
    def transfer_funds(cls, from_account_id, to_account_id, amount, currency="USD", reference_note=""):
        logger.info(
            f"Business Logic: Transferring {amount} {currency} "
            f"from {from_account_id} to {to_account_id}"
        )

        # Validate inputs
        if not from_account_id or not to_account_id:
            return {
                "status_code": "ERROR_INVALID_INPUT",
                "status_message": "Both source and destination account IDs are required.",
            }

        if from_account_id == to_account_id:
            return {
                "status_code": "ERROR_INVALID_INPUT",
                "status_message": "Source and destination accounts must be different.",
            }

        if amount is None or amount <= 0:
            return {
                "status_code": "ERROR_INVALID_AMOUNT",
                "status_message": "Transfer amount must be a positive number.",
            }

        from_account = accounts_db.get(from_account_id)
        to_account = accounts_db.get(to_account_id)

        if from_account is None:
            return {
                "status_code": "ERROR_NOT_FOUND",
                "status_message": f"Source account '{from_account_id}' not found.",
            }

        if to_account is None:
            return {
                "status_code": "ERROR_NOT_FOUND",
                "status_message": f"Destination account '{to_account_id}' not found.",
            }

        if not from_account["is_active"]:
            return {
                "status_code": "ERROR_INACTIVE_ACCOUNT",
                "status_message": f"Source account '{from_account_id}' is inactive.",
            }

        if not to_account["is_active"]:
            return {
                "status_code": "ERROR_INACTIVE_ACCOUNT",
                "status_message": f"Destination account '{to_account_id}' is inactive.",
            }

        if from_account["balance"] < amount:
            return {
                "status_code": "ERROR_INSUFFICIENT_FUNDS",
                "status_message": (
                    f"Insufficient funds in account '{from_account_id}'. "
                    f"Available: {from_account['balance']} {from_account['currency']}, "
                    f"Requested: {amount} {currency}."
                ),
            }

        # Execute the transfer
        from_account["balance"] -= amount
        to_account["balance"] += amount

        transaction_id = cls._generate_transaction_id()
        now = datetime.utcnow()

        record = {
            "transaction_id": transaction_id,
            "from_account_id": from_account_id,
            "to_account_id": to_account_id,
            "amount": amount,
            "currency": currency,
            "reference_note": reference_note or "",
            "timestamp": now,
        }
        transaction_log.append(record)

        logger.info(f"Transfer successful: {transaction_id}")

        return {
            "status_code": "SUCCESS",
            "status_message": "Transfer completed successfully.",
            "transaction_id": transaction_id,
            "from_account_id": from_account_id,
            "to_account_id": to_account_id,
            "amount": amount,
            "currency": currency,
            "timestamp": now,
            "from_new_balance": from_account["balance"],
            "to_new_balance": to_account["balance"],
        }

    @staticmethod
    def get_account_info(account_id):
        logger.info(f"Business Logic: Getting account info for {account_id}")

        if not account_id or account_id.strip() == "":
            return {
                "status_code": "ERROR_INVALID_INPUT",
                "status_message": "Account ID cannot be empty.",
            }

        account = accounts_db.get(account_id)
        if account is None:
            return {
                "status_code": "ERROR_NOT_FOUND",
                "status_message": f"Account '{account_id}' not found.",
            }

        return {
            "status_code": "SUCCESS",
            "status_message": "Account info retrieved successfully.",
            **account,
        }

    @staticmethod
    def get_transaction_history(account_id, limit=50):
        logger.info(f"Business Logic: Getting transaction history for {account_id}")

        if not account_id or account_id.strip() == "":
            return {
                "status_code": "ERROR_INVALID_INPUT",
                "status_message": "Account ID cannot be empty.",
            }

        account = accounts_db.get(account_id)
        if account is None:
            return {
                "status_code": "ERROR_NOT_FOUND",
                "status_message": f"Account '{account_id}' not found.",
            }

        relevant = [
            t for t in transaction_log
            if t["from_account_id"] == account_id or t["to_account_id"] == account_id
        ]

        relevant.sort(key=lambda x: x["timestamp"], reverse=True)
        relevant = relevant[:int(limit)]

        return {
            "status_code": "SUCCESS",
            "status_message": "Transaction history retrieved successfully.",
            "account_id": account_id,
            "transactions": relevant,
            "total_transactions": len(relevant),
        }

    @staticmethod
    def list_accounts(active_only=True):
        logger.info(f"Business Logic: Listing accounts (active_only={active_only})")

        results = []
        for acc in accounts_db.values():
            if active_only and not acc["is_active"]:
                continue
            results.append(acc)

        return {
            "status_code": "SUCCESS",
            "status_message": "Accounts listed successfully.",
            "accounts": results,
            "total_accounts": len(results),
        }


