class FinancialService(Service):
    """SOAP service exposing financial operations with SOAPAction routing."""

    @rpc(
        Unicode(min_occurs=1),
        _returns=BalanceResponse,
        _soap_action="http://financial.services.api/getBalance",
        _operation_name="getBalance",
    )
    def getBalance(ctx, account_id):
        """
        Get the current balance for a given account.

        SOAPAction: http://financial.services.api/getBalance
        """
        logger.info(f"SOAP Operation: getBalance called for account_id={account_id}")

        result = FinancialBusinessLogic.get_balance(account_id)

        response = BalanceResponse()
        response.status_code = result.get("status_code", "UNKNOWN")
        response.status_message = result.get("status_message", "")
        response.account_id = result.get("account_id", account_id)
        response.balance = result.get("balance", Decimal("0.00"))
        response.currency = result.get("currency", "USD")
        response.as_of = datetime.utcnow()

        return response

    @rpc(
        Unicode(min_occurs=1),
        Unicode(min_occurs=1),
        SpyneDecimal(min_occurs=1),
        Unicode,
        Unicode,
        _returns=TransferResponse,
        _soap_action="http://financial.services.api/transferFunds",
        _operation_name="transferFunds",
    )
    def transferFunds(ctx, from_account_id, to_account_id, amount, currency, reference_note):
        """
        Transfer funds between two accounts.

        SOAPAction: http://financial.services.api/transferFunds
        """
        logger.info(
            f"SOAP Operation: transferFunds called: "
            f"{from_account_id} -> {to_account_id}, amount={amount}"
        )

        if currency is None or currency.strip() == "":
            currency = "USD"

        result = FinancialBusinessLogic.transfer_funds(
            from_account_id=from_account_id,
            to_account_id=to_account_id,
            amount=amount,
            currency=currency,
            reference_note=reference_note or "",
        )

        response = TransferResponse()
        response.status_code = result.get("status_code", "UNKNOWN")
        response.status_message = result.get("status_message", "")
        response.transaction_id = result.get("transaction_id", "")
        response.from_account_id = result.get("from_account_id", from_account_id)
        response.to_account_id = result.get("to_account_id", to_account_id)
        response.amount = result.get("amount", amount)
        response.currency = result.get("currency", currency)
        response.timestamp = result.get("timestamp", datetime.utcnow())
        response.from_new_balance = result.get("from_new_balance", Decimal("0.00"))
        response.to_new_balance = result.get("to_new_balance", Decimal("0.00"))

        return response

    @rpc(
        Unicode(min_occurs=1),
        _returns=AccountInfo,
        _soap_action="http://financial.services.api/getAccountInfo",
        _operation_name="getAccountInfo",
    )
    def getAccountInfo(ctx, account_id):
        """
        Get detailed account information.

        SOAPAction: http://financial.services.api/getAccountInfo
        """
        logger.info(f"SOAP Operation: getAccountInfo called for account_id={account_id}")

        result = FinancialBusinessLogic.get_account_info(account_id)

        response = AccountInfo()
        response.status_code = result.get("status_code", "UNKNOWN")
        response.status_message = result.get("status_message", "")
        response.account_id = result.get("account_id", account_id)
        response.owner_name = result.get("owner_name", "")
        response.email = result.get("email", "")
        response.balance = result.get("balance", Decimal("0.00"))
        response.currency = result.get("currency", "USD")
        response.account_type = result.get("account_type", "")
        response.created_at = result.get("created_at")
        response.is_active = result.get("is_active", False)

        return response

    @rpc(
        Unicode(min_occurs=1),
        SpyneDecimal,
        _returns=TransactionHistoryResponse,
        _soap_action="http://financial.services.api/getTransactionHistory",
        _operation_name="getTransactionHistory",
    )
    def getTransactionHistory(ctx, account_id, limit):
        """
        Get transaction history for an account.

        SOAPAction: http://financial.services.api/getTransactionHistory
        """
        logger.info(f"SOAP Operation: getTransactionHistory called for account_id={account_id}")

        if limit is None or limit <= 0:
            limit = 50

        result = FinancialBusinessLogic.get_transaction_history(account_id, limit)

        response = TransactionHistoryResponse()
        response.status_code = result.get("status_code", "UNKNOWN")
        response.status_message = result.get("status_message", "")
        response.account_id = result.get("account_id", account_id)
        response.total_transactions = result.get("total_transactions", 0)

        tx_list = []
        for tx_data in result.get("transactions", []):
            tx = TransactionRecord()
            tx.transaction_id = tx_data["transaction_id"]
            tx.from_account_id = tx_data["from_account_id"]
            tx.to_account_id = tx_data["to_account_id"]
            tx.amount = tx_data["amount"]
            tx.currency = tx_data["currency"]
            tx.reference_note = tx_data.get("reference_note", "")
            tx.timestamp = tx_data["timestamp"]
            tx_list.append(tx)

        response.transactions = tx_list

        return response

    @rpc(
        Boolean,
        _returns=AccountListResponse,
        _soap_action="http://financial.services.api/listAccounts",
        _operation_name="listAccounts",
    )
    def listAccounts(ctx, active_only):
        """
        List all accounts, optionally filtering by active status.

        SOAPAction: http://financial.services.api/listAccounts
        """
        logger.info(f"SOAP Operation: listAccounts called (active_only={active_only})")

        if active_only is None:
            active_only = True

        result = FinancialBusinessLogic.list_accounts(active_only)

        response = AccountListResponse()
        response.status_code = result.get("status_code", "UNKNOWN")
        response.status_message = result.get("status_message", "")
        response.total_accounts = result.get("total_accounts", 0)

        acc_list = []
        for acc_data in result.get("accounts", []):
            acc = AccountInfo()
            acc.account_id = acc_data["account_id"]
            acc.owner_name = acc_data["owner_name"]
            acc.email = acc_data["email"]
            acc.balance = acc_data["balance"]
            acc.currency = acc_data["currency"]
            acc.account_type = acc_data["account_type"]
            acc.created_at = acc_data["created_at"]
            acc.is_active = acc_data["is_active"]
            acc.status_code = "SUCCESS"
            acc.status_message = ""
            acc_list.append(acc)

        response.accounts = acc_list

        return response


# --- Application Setup ---

def create_spyne_application():
    """Create and configure the Spyne SOAP application."""
    app = Application(
        services=[FinancialService],
        tns="financial.services.api",
        name="FinancialServicesAPI",
        in_protocol=Soap11(validator="lxml"),
        out_protocol=Soap11(),
    )
    return app


def create_wsgi_application():
    """Create the WSGI-compatible application."""
    spyne_app = create_spyne_application()
    wsgi_app = WsgiApplication(spyne_app)
    return wsgi_app


